{"command": "cd /tmp/sv-57bf3fcf59d347ac9bd746ab08ba72eb/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                key = (name, fw['framework'], p['id'])
                result[key] = p['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append((key, bv, av))
    else:
        unchanged.append((key, bv))

print('CHANGES:')
for (proj, fw, pkg), bv, av in changes:
    print(f'  {proj:20s} {fw:12s} {pkg:50s} {bv or \"(none)\":>12s} -> {av or \"(none)\":<12s}')

print(f'\nUNCHANGED: {len(unchanged)} packages resolve identically')
"", "description": "Compare baseline vs post-CPM", "initial_wait": 15}
